output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?series ?seriesLabel ?startYear ?endYear WHERE {
  wd:Q191828 wdt:P161 ?series .
  ?series wdt:P31 wd:Q5398426 .
  OPTIONAL {
    ?series rdfs:label ?seriesLabel .
    FILTER(LANG(?seriesLabel) = "en")
    .
  }
  OPTIONAL {
    ?series wdt:P580 ?start .
  }
  OPTIONAL {
    ?series wdt:P582 ?end .
  }
  BIND(IF(BOUND(?start) , SUBSTR(STR(?start) , 1 , 4) , "") AS ?startYear)
  BIND(IF(BOUND(?end) , SUBSTR(STR(?end) , 1 , 4) , "") AS ?endYear)
}
